Actionscript.script:
onClipEvent(enterFrame){
   镜闪时间许可 = true;
   镜闪时间间隔 = 0.25;
   耗蓝比例 = 2;
   自机 = _root.获得父节点(this,5);
   当前时间 = getTimer();
   if(isNaN(自机.上次镜闪时间) or 当前时间 - 自机.上次镜闪时间 > 镜闪时间间隔 * 1000)
   {
      缓存时间 = 自机.上次镜闪时间;
      自机.上次镜闪时间 = 当前时间;
   }
   else
   {
      镜闪时间许可 = false;
   }
   if(_root.兵器攻击检测(自机) and 镜闪时间许可)
   {
      镜闪许可 = true;
      switch(自机.getSmallState())
      {
         case "兵器二段中":
         case "兵器三段中":
         case "兵器四段中":
         case "兵器五段中":
            镜闪许可 = true;
            break;
         default:
            镜闪许可 = _root.成功率(5);
      }
      if(镜闪许可)
      {
         _root.镜闪变亮(镜闪时间间隔 * 1000 / 2,自机);
         自机.man.攻击时移动(0,360);
         自机.man.攻击时可改变移动方向(1);
         耗蓝量 = Math.floor(自机.mp满血值 / 100 * 耗蓝比例);
         if(自机.mp >= 耗蓝量)
         {
            自机.mp -= 耗蓝量;
            var myPoint = {x:this._x,y:this._y};
            _parent.localToGlobal(myPoint);
            _root.gameworld.globalToLocal(myPoint);
            声音 = "";
            霰弹值 = 1;
            子弹散射度 = 0;
            发射效果 = "";
            子弹种类 = "镜闪";
            子弹威力 = 耗蓝量 * 40;
            子弹速度 = 0;
            击中地图效果 = "";
            Z轴攻击范围 = 150;
            击倒率 = 100;
            击中后子弹的效果 = "";
            子弹敌我属性 = true;
            发射者名 = 自机._name;
            子弹敌我属性值 = 自机.是否为敌人 == true ? false : true;
            shootX = myPoint.x;
            Z轴坐标 = shootY = 自机._y;
            _root.子弹区域shoot(声音,霰弹值,子弹散射度,发射效果,子弹种类,子弹威力,子弹速度,Z轴攻击范围,击中地图效果,发射者名,shootX,shootY,Z轴坐标,子弹敌我属性值,击倒率,击中后子弹的效果);
         }
         else if(自机 == root.gameworld[_root.控制目标])
         {
            root.发布消息("气力不足，难以发挥武器的真正力量……");
         }
      }
   }
}
